// Define a type for the graph edge structure
struct Edge {
    int to;
    long long cost; // Cost when empty-handed (cost)
    int tax;        // Tax multiplier
};

// Define a structure for Dijkstra's priority queue elements
struct State {
    long long distance;
    int node;

    // Overload '>' for min-heap behavior in C++'s std::priority_queue
    bool operator>(const State& other) const {
        return distance > other.distance;
    }
};

// Function to compute shortest paths using Dijkstra's algorithm
// Finds shortest path from a source node to all other nodes given specific edge weights.
vector<long long> dijkstra(int n, const vector<vector<Edge>>& adj, const vector<tuple<int, int, long long, int>>& road_data, int start_node, bool carrying_apple) {
    vector<long long> dist(n, numeric_limits<long long>::max());
    priority_queue<State, vector<State>, greater<State>> pq;

    dist[start_node] = 0;
    pq.push({0, start_node});

    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();

        long long d = current.distance;
        int u = current.node;

        if (d > dist[u]) {
            continue;
        }

        // Iterate over all edges connected to u
        for (const auto& edge : adj[u]) {
            int v = edge.to;
            long long travel_cost;

            if (!carrying_apple) {
                // Empty-handed: cost = cost_i
                travel_cost = edge.cost;
            } else {
                // Carrying apple: cost = cost_i * tax_i
                travel_cost = edge.cost * edge.tax;
            }

            if (dist[u] != numeric_limits<long long>::max() && dist[u] + travel_cost < dist[v]) {
                dist[v] = dist[u] + travel_cost;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}

// Helper function to run Dijkstra for all-pairs shortest path calculations needed
// For this problem, we need two sets of shortest paths:
// 1. Path from j to i while empty-handed (Cost: cost_i) -> Needed for travel from j to i
// 2. Path from i to j while carrying apples (Cost: cost_i * tax_i) -> Needed for travel from i to j
// Since roads are bidirectional, the shortest path from A to B is the same as B to A in terms of path structure, 
// but the cost calculation depends on the state (empty/carrying).

// The problem structure implies we need:
// 1. min_cost_empty(j -> i): Shortest path cost from j to i without apples.
// 2. min_cost_carry(i -> j): Shortest path cost from i to j with apples.

// Since edges are bidirectional:
// min_cost_empty(j -> i) = shortest path from j to i using base costs.
// min_cost_carry(i -> j) = shortest path from i to j using weighted costs.


// We can run Dijkstra N times for the "empty" case and N times for the "carrying" case.
// However, since the graph structure is fixed, we can build two separate adjacency lists:
// adj_empty: edge weight = cost_i
// adj_carry: edge weight = cost_i * tax_i

struct WeightedEdge {
    int to;
    long long weight;
};

// Dijkstra specialized for a single weight type
vector<long long> dijkstra_single_weight(int n, const vector<vector<WeightedEdge>>& adj, int start_node) {
    vector<long long> dist(n, numeric_limits<long long>::max());
    priority_queue<State, vector<State>, greater<State>> pq;

    dist[start_node] = 0;
    pq.push({0, start_node});

    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();

        long long d = current.distance;
        int u = current.node;

        if (d > dist[u]) {
            continue;
        }

        for (const auto& edge : adj[u]) {
            int v = edge.to;
            long long weight = edge.weight;

            if (dist[u] != numeric_limits<long long>::max() && dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}


vector<long long> solve(long long n_ll, vector<long long> prices, vector<vector<long long>> roads) {
    int n = (int)n_ll;

    // Adjacency list for empty-handed travel (weight = cost_i)
    vector<vector<WeightedEdge>> adj_empty(n);
    // Adjacency list for carrying-apple travel (weight = cost_i * tax_i)
    vector<vector<WeightedEdge>> adj_carry(n);

    for (const auto& road : roads) {
        int u = (int)road[0];
        int v = (int)road[1];
        long long cost = road[2];
        int tax = (int)road[3];

        // For both directions (u <-> v)

        // Empty travel: cost = cost
        adj_empty[u].push_back({v, cost});
        adj_empty[v].push_back({u, cost});

        // Carrying travel: cost = cost * tax
        long long carry_cost = cost * tax;
        adj_carry[u].push_back({v, carry_cost});
        adj_carry[v].push_back({u, carry_cost});
    }

    // 1. Precompute all-pairs shortest paths (APSP)

    // dist_empty[j][i]: Shortest path cost from j to i while empty-handed.
    // Since roads are bidirectional, this is the same as i to j.
    vector<vector<long long>> dist_empty(n, vector<long long>(n));
    for (int j = 0; j < n; ++j) {
        // Run Dijkstra starting at j using empty weights
        vector<long long> d = dijkstra_single_weight(n, adj_empty, j);
        for (int i = 0; i < n; ++i) {
            dist_empty[j][i] = d[i];
        }
    }

    // dist_carry[i][j]: Shortest path cost from i to j while carrying apples.
    vector<vector<long long>> dist_carry(n, vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        // Run Dijkstra starting at i using carrying weights
        vector<long long> d = dijkstra_single_weight(n, adj_carry, i);
        for (int j = 0; j < n; ++j) {
            dist_carry[i][j] = d[j];
        }
    }

    // 2. Calculate the minimum cost for each shop i
    vector<long long> ans(n);

    for (int i = 0; i < n; ++i) {
        // Option 1: Buy directly at shop i
        long long min_cost = prices[i];

        // Option 2: Travel from i, buy at j, return to i
        // Total Cost = Cost(i -> j, empty) + prices[j] + Cost(j -> i, carry)

        for (int j = 0; j < n; ++j) {
            if (i == j) continue;

            long long travel_to_j_empty = dist_empty[i][j];
            long long travel_back_from_j_carry = dist_carry[j][i];

            // Check if paths exist
            if (travel_to_j_empty != numeric_limits<long long>::max() && 
                travel_back_from_j_carry != numeric_limits<long long>::max()) 
            {
                long long total_cost = travel_to_j_empty + prices[j] + travel_back_from_j_carry;
                min_cost = min(min_cost, total_cost);
            }
        }

        ans[i] = min_cost;
    }

    return ans;
}
