    // Given the problem structure, we need SSSP from *every* node to find min path for 'no apple' journey.
    // However, the problem is about minimizing total cost: prices[j] + cost_path(i->j) + cost_path(j->i).
    // The "no apple" path is i -> j (cost_no_apple) and the "with apple" path is j -> i (cost_with_apple).
    // The paths are independent, so we need shortest path for both scenarios.

    // Since we need this for *all* origins, we should precalculate All-Pairs Shortest Path (APSP) for both scenarios.
    // Since N is up to 1000, Floyd-Warshall O(N^3) is too slow (10^9).
    // N runs of Dijkstra O(N * (E + N log N)) might be feasible. E <= 2000.
    // 1000 * (2000 + 1000 * log 1000) ~ 1000 * 2000 = 2 * 10^6 operations per run, total ~ 2 * 10^9? No.
    // E is at most 2000. For Dijkstra: O(E log N) or O(N^2) if using array for priority queue.
    // Using binary heap: O(E log N). E <= 2000. N <= 1000.
    // 1000 * (2000 * log 1000) ~ 1000 * 2000 * 10 = 2 * 10^7. This is feasible.

    // We will run Dijkstra N times externally. This helper function will assume a single source is provided.
}

// Dijkstra's algorithm for a single source
void dijkstra(int start_node, int n, const vector<vector<Edge>>& adj, vector<long long>& dist) {
    dist.assign(n, LLONG_MAX);
    dist[start_node] = 0;
    // Priority queue stores {distance, node}
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;
    pq.push({0, start_node});

    while (!pq.empty()) {
        long long d = pq.top().first;
        int u = pq.top().second;
        pq.pop();

        if (d > dist[u]) {
            continue;
        }

        for (const auto& edge : adj[u]) {
            int v = edge.to;
            // The cost structure depends on the state (carrying apple or not).
            // When running for "no apple" path (i -> j), the cost is edge.cost.
            // When running for "with apple" path (j -> i), the cost is edge.tax * cost_original.
            // Since we are calculating shortest path based on the edge weight for the specific journey type:
            long long weight = edge.cost; // This needs to be adapted based on which graph we are using (adj_no_apple or adj_with_apple)

            // For the purpose of generic Dijkstra, we assume the graph edges already reflect the weights for this specific travel type.
            // Since we will build two distinct adjacency lists (one for 'no apple' travel, one for 'with apple' travel),
            // this single Dijkstra implementation should work if we pass the correct adjacency list.

            if (dist[u] != LLONG_MAX && dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                pq.push({dist[v], v});
            }
        }
    }
}


// Structure to hold all-pairs shortest paths results
struct APSP_Results {
    // dist_no_apple[i][j]: shortest path cost from i to j without apple
    vector<vector<long long>> dist_no_apple; 
    // dist_with_apple[i][j]: shortest path cost from i to j while carrying apple
    vector<vector<long long>> dist_with_apple; 
};

APSP_Results calculate_all_pairs_shortest_paths(int n, const vector<tuple<int, int, long long, long long>>& roads) {
    // 1. Build Adjacency Lists for both scenarios
    // Graph for "No Apple" travel: Weight is cost_i
    vector<vector<Edge>> adj_no_apple(n);
    // Graph for "With Apple" travel: Weight is cost_i * tax_i
    vector<vector<Edge>> adj_with_apple(n);

    for (const auto& road : roads) {
        int u, v;
        long long cost, tax;
        tie(u, v, cost, tax) = road;

        // Road is bidirectional

        // No Apple Travel (u <-> v): Cost is 'cost'
        adj_no_apple[u].push_back({v, cost, tax});
        adj_no_apple[v].push_back({u, cost, tax});

        // With Apple Travel (u <-> v): Cost is 'cost * tax'
        // Note: The problem states the return path cost is "cost * tax".
        long long taxed_cost = cost * tax;

        // For the 'with apple' graph, we treat the effective weight as taxed_cost.
        // We reuse the Edge structure but conceptually, the 'cost' field now holds the effective weight for this path type.
        adj_with_apple[u].push_back({v, taxed_cost, tax}); 
        adj_with_apple[v].push_back({u, taxed_cost, tax});
    }

    // 2. Run N instances of Dijkstra for No Apple path (i -> j)
    APSP_Results results;
    results.dist_no_apple.assign(n, vector<long long>(n));

    for (int i = 0; i < n; ++i) {
        vector<long long> dist_i;
        dijkstra(i, n, adj_no_apple, dist_i);
        for (int j = 0; j < n; ++j) {
            results.dist_no_apple[i][j] = dist_i[j];
        }
    }

    // 3. Run N instances of Dijkstra for With Apple path (j -> i)
    results.dist_with_apple.assign(n, vector<long long>(n));

    for (int j = 0; j < n; ++j) {
        vector<long long> dist_j;
        dijkstra(j, n, adj_with_apple, dist_j);
        // Store in results.dist_with_apple[j][i] = shortest path cost from j to i (which is what we need for return leg)
        for (int i = 0; i < n; ++i) {
            results.dist_with_apple[j][i] = dist_j[i];
        }
    }

    return results;
}


// Main solver function adhering to the signature
vector<long long> solve(long long n_ll, vector<long long> prices, vector<vector<long long>> roads) {
    int n = (int)n_ll;

    // Convert roads format to tuple for easier processing in APSP
    vector<tuple<int, int, long long, long long>> road_tuples;
    for (const auto& road : roads) {
        road_tuples.emplace_back(
            (int)road[0], (int)road[1], road[2], road[3]
        );
    }

    // Calculate APSP
    APSP_Results apsp = calculate_all_pairs_shortest_paths(n, road_tuples);

    vector<long long> ans(n);

    // Calculate the minimum cost for each store i
    for (int i = 0; i < n; ++i) {
        // Option 1: Buy directly at store i
        long long min_cost = prices[i];

        // Option 2: Buy at store j (j != i), travel i -> j (no apple), then j -> i (with apple)
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;

            // Cost = Price[j] + Travel_Cost(i -> j, no apple) + Travel_Cost(j -> i, with apple)

            long long cost_i_to_j_no_apple = apsp.dist_no_apple[i][j];
            long long cost_j_to_i_with_apple = apsp.dist_with_apple[j][i];

            // Check for reachability
            if (cost_i_to_j_no_apple != LLONG_MAX && cost_j_to_i_with_apple != LLONG_MAX) {
                long long total_cost = prices[j] + cost_i_to_j_no_apple + cost_j_to_i_with_apple;
                min_cost = min(min_cost, total_cost);
            }
        }
        ans[i] = min_cost;
    }

    return ans;
}
